#!/bin/bash
set -euo pipefail

echo "============================================="
echo "  Website Auditor - Deploy v12 (Cache Bust)"
echo "============================================="

cd ~/chaos_tester 2>/dev/null || { git clone https://github.com/SpikeyCoder/chaos_tester.git ~/chaos_tester && cd ~/chaos_tester; }
git checkout main && git pull origin main 2>/dev/null || true


mkdir -p templates
echo '' | base64 -d > templates/base.html

mkdir -p templates
echo '' | base64 -d > templates/dashboard.html

mkdir -p templates
echo '' | base64 -d > templates/report.html

mkdir -p templates
echo '' | base64 -d > templates/features.html

mkdir -p templates
echo '' | base64 -d > templates/how_it_works.html

mkdir -p templates
echo '' | base64 -d > templates/404.html

mkdir -p static/js
echo '' | base64 -d > static/js/dashboard.js

mkdir -p modules
echo '' | base64 -d > modules/performance.py

echo '' | base64 -d > app.py

echo '' | base64 -d > Dockerfile

# Add a cache-busting ARG to the Dockerfile to force fresh COPY layer
sed -i '/^COPY \. \.\/chaos_tester\//i ARG CACHE_BUST=1' Dockerfile

echo ""
echo "✅ All files written. Verifying Python syntax..."
python3 -c "import ast; ast.parse(open('modules/performance.py').read()); print('  performance.py: OK')"
python3 -c "import ast; ast.parse(open('app.py').read()); print('  app.py: OK')"

echo ""
echo "Committing and pushing..."

git add -A
git commit -m "fix: force cache bust + QA fixes at correct root paths

- Force Docker layer cache invalidation with ARG CACHE_BUST
- Bump dashboard.js cache buster to v=3
- All QA fixes: 404 page, hamburger menu, progress overlay,
  favicon, skip link, ARIA labels, FAQ accordion, table sorting,
  noindex on reports, copy button, sitemap lastmod, badge icons
- Fix corrupted performance.py line 77
" || echo "Nothing to commit"

git push origin main

echo ""
echo "🚀 Deploying to Cloud Run (with --no-cache)..."
gcloud builds submit --tag gcr.io/chaos-tester/chaos-tester --project chaos-tester --no-cache

gcloud run deploy chaos-tester \
  --project chaos-tester \
  --image gcr.io/chaos-tester/chaos-tester \
  --region us-central1 \
  --allow-unauthenticated \
  --memory 512Mi \
  --timeout 300

echo ""
echo "✅ Deployment complete!"
echo "   https://website-auditor.io"

